class Solution {
    public List<String> findRepeatedDnaSequences(String s) {
        int[] count = new int[26];
        String lowerCaseSequence = s.toLowerCase();
        for (int i = 0; i < lowerCaseSequence.length(); i++) {
            char c = lowerCaseSequence.charAt(i);
            if (c >= 'a' && c <= 'z') {
                count[c - 'a']++;
            }
        }
        List<String> result = new ArrayList<>();
        for (int i = 0; i < 26; i++) {
            if (count[i] > 1) {
                StringBuilder sb = new StringBuilder();
                for (int j = 0; j < lowerCaseSequence.length(); j++) {
                    if (lowerCaseSequence.charAt(j) == i + 'a') {
                        sb.append(i + 'a');
                    }
                }
                result.add(sb.toString());
            }
        }
        return result;
    }
}
